using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalSentenceCount { get; set; }

    public int SummarySentenceCount { get; set; }
}

using DocSummary.Models;

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    SummarizeResponse Summarize(SummarizeRequest request);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

public partial class DocumentSummaryService : IDocumentSummaryService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "it", "its",
        "this", "that", "these", "those", "be", "been", "being", "have",
        "has", "had", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "shall", "can", "not", "no", "so",
        "if", "then", "than", "as", "from", "into", "about", "between"
    };

    public SummarizeResponse Summarize(SummarizeRequest request)
    {
        var sentences = SplitIntoSentences(request.DocumentText);

        if (sentences.Count == 0)
        {
            return new SummarizeResponse
            {
                Summary = string.Empty,
                OriginalSentenceCount = 0,
                SummarySentenceCount = 0
            };
        }

        int targetCount = Math.Min(request.MaxSentences, sentences.Count);

        // For very short documents, return as-is.
        if (sentences.Count <= targetCount)
        {
            return new SummarizeResponse
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        var wordFrequencies = BuildWordFrequencies(sentences);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        // Pick top-scored sentences, preserving their original order.
        var topIndices = sentenceScores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(targetCount)
            .Select(x => x.index)
            .Order()
            .ToList();

        var summarySentences = topIndices.Select(i => sentences[i]);

        return new SummarizeResponse
        {
            Summary = string.Join(" ", summarySentences),
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = targetCount
        };
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceBoundary().Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (StopWords.Contains(word) || word.Length < 2)
                    continue;

                if (!freq.TryAdd(word, 1))
                    freq[word]++;
            }
        }

        return freq;
    }

    private static List<double> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = TokenizeWords(sentence);
            if (words.Length == 0)
            {
                scores.Add(0);
                continue;
            }

            double score = words
                .Where(w => !StopWords.Contains(w) && w.Length >= 2)
                .Sum(w => wordFrequencies.GetValueOrDefault(w, 0));

            // Normalize by word count to avoid bias toward long sentences.
            scores.Add(score / words.Length);
        }

        return scores;
    }

    private static string[] TokenizeWords(string text)
    {
        return WordToken().Matches(text)
            .Select(m => m.Value)
            .ToArray();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\w+", RegexOptions.Compiled)]
    private static partial Regex WordToken();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
